const __pageData = JSON.parse('{"title":"安全测试：攻防验证","description":"系统阐述安全测试的理论分类体系（SAST/DAST/IAST/Fuzzing），深入剖析OWASP Testing Guide方法论与威胁建模驱动的测试策略，并全面映射到JS/TS生态中的Snyk、OWASP ZAP、 secrets检测与CI集成工程实践。","frontmatter":{"title":"安全测试：攻防验证","description":"系统阐述安全测试的理论分类体系（SAST/DAST/IAST/Fuzzing），深入剖析OWASP Testing Guide方法论与威胁建模驱动的测试策略，并全面映射到JS/TS生态中的Snyk、OWASP ZAP、 secrets检测与CI集成工程实践。","date":"2026-05-01T00:00:00.000Z","tags":["测试工程","安全测试","SAST","DAST","OWASP","渗透测试"," secrets检测"],"category":"engineering"},"headers":[],"relativePath":"testing-engineering/09-security-testing.md","filePath":"testing-engineering/09-security-testing.md","lastUpdated":1777741461000}');
